#include <iostream>

class StepCounter {
    int m_steps{};
public:
    explicit StepCounter(int steps) : m_steps{ steps } {}
    int get() const { return m_steps; }

    StepCounter& operator++() {
        ++m_steps;
        return *this;
    }

    StepCounter operator++(int) {
        StepCounter old{ *this };
        ++(*this);
        return old;
    }
};

int main() {
    int init{}, p{}, q{};
    std::cin >> init >> p >> q;
    StepCounter counter{ init };

    int lastPrefix = counter.get();
    for (int i = 0; i < p; ++i)
